using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

class MyTypeEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(
        ITypeDescriptorContext? context,
        IServiceProvider? provider,
        object? value)
    {
        if (provider?.GetService(typeof(IWindowsFormsEditorService))
            is not IWindowsFormsEditorService editorService)
        {
            return value;
        }

        Control? dropDown = CreateDropDownControl(value);

        // .NET 9: DropDownControl now throws ArgumentNullException when passed null.
        // Guard against null before calling.
        if (dropDown is not null)
        {
            editorService.DropDownControl(dropDown);
            value = GetValueFromControl(dropDown);
        }

        return value;
    }

    private static Control? CreateDropDownControl(object? currentValue)
    {
        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { "Option A", "Option B", "Option C" });
        if (currentValue is string s)
        {
            listBox.SelectedItem = s;
        }
        return listBox;
    }

    private static object? GetValueFromControl(Control control)
        => control is ListBox lb ? lb.SelectedItem : null;
}

